import React, { useEffect, useState } from 'react';

const columns = [
	{ label: 'Collection ID', key: 'collection_id' },
	{ label: 'Customer ID', key: 'customer_id' },
	{ label: 'Customer Name', key: 'customer_name' },
	{ label: 'Loan ID', key: 'loan_id' },
	{ label: 'Collected Date', key: 'collection_date' },
	{ label: 'Collected Amount', key: 'collection_amount' },
	{ label: 'Collection Type', key: 'collection_type' },
	{ label: 'Collected By', key: 'collected_by_name' },
];

const modalStyle = {
	position: 'fixed',
	top: 0,
	left: 0,
	width: '100vw',
	height: '100vh',
	background: 'rgba(0,0,64,0.2)',
	display: 'flex',
	alignItems: 'center',
	justifyContent: 'center',
	zIndex: 1000,
};

const formBoxStyle = {
	background: '#fff',
	padding: 32,
	borderRadius: 8,
	minWidth: 350,
	boxShadow: '0 2px 16px rgba(0,0,0,0.15)',
};

const initialForm = {
	customer_id: '',
	loan_id: '',
	collection_date: '',
	collection_amount: '',
	collection_type: '',
	collected_by_name: '',
};


const Collections = () => {
	// Helper to format date as DDMMMYYYY (e.g., 24APR2026)
	function formatDate(dateStr) {
		const date = new Date(dateStr);
		if (isNaN(date)) return dateStr;
		const day = String(date.getDate()).padStart(2, '0');
		const month = date.toLocaleString('en-US', { month: 'short' }).toUpperCase();
		const year = date.getFullYear();
		return `${day}${month}${year}`;
	}

	const [data, setData] = useState([]);
	const [loading, setLoading] = useState(true);
	const [showModal, setShowModal] = useState(false);
	const [form, setForm] = useState(initialForm);
	const [formError, setFormError] = useState('');
	const [customers, setCustomers] = useState([]);

	// Fetch collections
	const fetchCollections = () => {
		setLoading(true);
		fetch('http://localhost:4000/api/collections')
			.then(res => res.json())
			.then(json => {
				setData(Array.isArray(json) ? json : []);
				setLoading(false);
			})
			.catch(() => setLoading(false));
	};

	// Fetch customers when modal opens
	useEffect(() => {
		if (showModal) {
			fetch('http://localhost:4000/api/customers')
				.then(res => res.json())
				.then(json => setCustomers(Array.isArray(json) ? json : []));
		}
	}, [showModal]);

	useEffect(() => {
		fetchCollections();
	}, []);


	// Handle form input
	const handleFormChange = e => {
		setForm({ ...form, [e.target.name]: e.target.value });
	};

	// Handle customer select
	const handleCustomerChange = e => {
		const selectedId = e.target.value;
		const selected = customers.find(c => c.customer_id === selectedId);
		setForm({
			...form,
			customer_id: selected ? selected.customer_id : '',
			customer_name: selected ? selected.customer_name : '',
		});
	};

	// Handle form submit
	const handleFormSubmit = async e => {
		e.preventDefault();
		setFormError('');
		// Basic validation
		if (!form.customer_id || !form.loan_id || !form.collection_date || !form.collection_amount || !form.collection_type || !form.collected_by_name) {
			setFormError('All fields are required.');
			return;
		}
		// POST to backend (assume endpoint exists)
		try {
			const res = await fetch('http://localhost:4000/api/collections', {
				method: 'POST',
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify(form),
			});
			if (!res.ok) throw new Error('Failed to add collection');
			setShowModal(false);
			setForm(initialForm);
			fetchCollections();
		} catch (err) {
			setFormError('Failed to add collection.');
		}
	};

	if (loading) return null;

		// Calculate sum total for collected amount
		const totalCollected = data.reduce((sum, row) => sum + (parseFloat(row.collection_amount) || 0), 0);

		return (
			<div style={{ padding: 24 }}>
				<h2 style={{ color: 'navy', marginBottom: 20 }}>Collections</h2>

				{/* Header row for buttons and filters */}
				<div style={{ display: 'flex', gap: 12, marginBottom: 16 }}>
					<button onClick={() => setShowModal(true)}>Add Collection</button>
					<button>Export</button>
					<button onClick={fetchCollections}>Refresh</button>
								{/* Modal for Add Collection */}
								{showModal && (
									<div style={modalStyle}>
										<div style={formBoxStyle}>
											<h3 style={{ marginTop: 0, color: 'navy' }}>Add Collection</h3>
											<form onSubmit={handleFormSubmit}>
												<div style={{ marginBottom: 10 }}>
													<input
														name="customer_search"
														value={form.customer_search || ''}
														onChange={e => {
															setForm({ ...form, customer_search: e.target.value });
														}}
														placeholder="Type code or name to search"
														style={{ width: '100%', padding: 6, marginBottom: 4 }}
														autoComplete="off"
													/>
													<select
														name="customer_id"
														value={form.customer_id}
														onChange={handleCustomerChange}
														style={{ width: '100%', padding: 6 }}
													>
														<option value="">Select Customer</option>
														{customers
															.filter(c => {
																const q = (form.customer_search || '').toLowerCase();
																return (
																	c.customer_id.toLowerCase().includes(q) ||
																	c.customer_name.toLowerCase().includes(q)
																);
															})
															.map(c => (
																<option key={c.customer_id} value={c.customer_id}>
																	{c.customer_id} - {c.customer_name}
																</option>
															))}
													</select>
												</div>
												<div style={{ marginBottom: 10 }}>
													<input name="loan_id" value={form.loan_id} onChange={handleFormChange} placeholder="Loan ID" style={{ width: '100%', padding: 6 }} />
												</div>
												<div style={{ marginBottom: 10 }}>
													<input name="collection_date" type="date" value={form.collection_date} onChange={handleFormChange} placeholder="Collection Date" style={{ width: '100%', padding: 6 }} />
												</div>
												<div style={{ marginBottom: 10 }}>
													<input name="collection_amount" value={form.collection_amount} onChange={handleFormChange} placeholder="Collection Amount" style={{ width: '100%', padding: 6 }} type="number" min="0" step="0.01" />
												</div>
												<div style={{ marginBottom: 10 }}>
													<input name="collection_type" value={form.collection_type} onChange={handleFormChange} placeholder="Collection Type" style={{ width: '100%', padding: 6 }} />
												</div>
												<div style={{ marginBottom: 10 }}>
													<input name="collected_by_name" value={form.collected_by_name} onChange={handleFormChange} placeholder="Collected By Name" style={{ width: '100%', padding: 6 }} />
												</div>
												{formError && <div style={{ color: 'red', marginBottom: 8 }}>{formError}</div>}
												<div style={{ display: 'flex', gap: 12, marginTop: 10 }}>
													<button type="submit" style={{ background: 'navy', color: '#fff', padding: '6px 18px', border: 'none', borderRadius: 4 }}>Add</button>
													<button type="button" onClick={() => { setShowModal(false); setForm(initialForm); setFormError(''); }}>Cancel</button>
												</div>
											</form>
										</div>
									</div>
								)}
					{/* Example filters (customize as needed) */}
					<input type="text" placeholder="Filter by Customer Name" style={{ marginLeft: 16, padding: 4 }} />
					<input type="date" placeholder="From Date" style={{ padding: 4 }} />
					<input type="date" placeholder="To Date" style={{ padding: 4 }} />
				</div>

				<table style={{ width: '100%', borderCollapse: 'collapse' }}>
					<thead>
						<tr>
							{columns.map(col => (
								<th key={col.key} style={{ borderBottom: '1px solid #ccc', padding: 8, textAlign: 'left' }}>{col.label}</th>
							))}
						</tr>
					</thead>
					<tbody>
						{data.map((row, idx) => (
							<tr key={idx}>
								{columns.map(col => (
									<td key={col.key} style={{ padding: 8, borderBottom: '1px solid #eee' }}>
										{col.key === 'collection_date' && row[col.key]
											? formatDate(row[col.key])
											: row[col.key]}
									</td>
								))}
							</tr>
						))}
					</tbody>
					{/* Footer row for sum total */}
					<tfoot>
						<tr style={{ position: 'sticky', bottom: 0, background: '#f9f9f9', zIndex: 2 }}>
							<td colSpan={5} style={{ textAlign: 'right', fontWeight: 'bold', padding: 8, background: '#f9f9f9', position: 'sticky', bottom: 0, zIndex: 2 }}>Total Collected Amount:</td>
							<td style={{ fontWeight: 'bold', padding: 8, background: '#f9f9f9', position: 'sticky', bottom: 0, zIndex: 2 }}>{totalCollected.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</td>
							<td colSpan={2} style={{ background: '#f9f9f9', position: 'sticky', bottom: 0, zIndex: 2 }}></td>
						</tr>
					</tfoot>
				</table>
			</div>
		);
};

export default Collections;
